+// preventing unbounded growth when sessions disconnect (#7209).
+func (r *Registry) RemoveSelectedAgent(sessionID string) {
+	if r == nil || sessionID == "" {
+		return
+	}
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	delete(r.selectedAgent, sessionID)
